#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { float x, y, z; } Vec;
typedef struct { Vec o, d; } Ray;
typedef struct { Vec p, n; float t; int hit; } Hit;

static Vec vc(float x, float y, float z){ Vec v; v.x=x; v.y=y; v.z=z; return v; }
static Vec vadd(Vec a, Vec b){ return vc(a.x+b.x, a.y+b.y, a.z+b.z); }
static Vec vsub(Vec a, Vec b){ return vc(a.x-b.x, a.y-b.y, a.z-b.z); }
static Vec vmul(Vec v, float s){ return vc(v.x*s, v.y*s, v.z*s); }
static float vdot(Vec a, Vec b){ return a.x*b.x + a.y*b.y + a.z*b.z; }
static float vlen(Vec v){ return sqrtf(v.x*v.x + v.y*v.y + v.z*v.z); }
static Vec vnorm(Vec v){ float l = vlen(v); return vc(v.x/l, v.y/l, v.z/l); }
static Ray ray_create(Vec o, Vec d){ Ray r; r.o=o; r.d=vnorm(d); return r; }

static Hit sphere_intersect(Ray ray, Vec center, float radius){
    Hit h; h.hit=0; h.t=0.0f; h.p=vc(0,0,0); h.n=vc(0,0,0);
    Vec oc = vsub(ray.o, center);
    float a = vdot(ray.d, ray.d);
    float b = 2.0f * vdot(oc, ray.d);
    float c = vdot(oc, oc) - radius*radius;
    float disc = b*b - 4.0f*a*c;
    if (disc < 0.0f) return h;
    float t = (-b - sqrt(disc)) / (2.0f*a);
    if (t < 0.001f){
        t = (-b + sqrt(disc)) / (2.0f*a);
        if (t < 0.001f) return h;
    }
    h.hit=1; h.t=t;
    h.p = vadd(ray.o, vmul(ray.d, t));
    h.n = vnorm(vsub(h.p, center));
    return h;
}

static Vec sky_color(Ray ray){
    float t = 0.5f * (ray.d.y + 1.0f);
    return vadd(vmul(vc(1.0f,1.0f,1.0f), 1.0f - t), vmul(vc(0.5f,0.7f,1.0f), t));
}

static int is_in_shadow(Vec point, Vec light, Vec center, float radius){
    Ray sr = ray_create(point, light);
    Hit h = sphere_intersect(sr, center, radius);
    return h.hit;
}

static Vec trace(Ray ray, Vec center, float radius, Vec light){
    Hit h = sphere_intersect(ray, center, radius);
    if (h.hit){
        float brightness = 0.2f;
        if (!is_in_shadow(h.p, light, center, radius)){
            float diff = fmax(0.0, vdot(h.n, light));
            brightness = 0.2f + 0.8f * diff;
        }
        return vmul(vc(1.0f, 0.2f, 0.2f), brightness);
    }
    if (fabsf(ray.d.y) > 0.0001f){
        float t = -1.5f / ray.d.y;
        if (t > 0.001f){
            Vec p = vadd(ray.o, vmul(ray.d, t));
            Vec n = vc(0.0f, 1.0f, 0.0f);
            float brightness = 0.2f;
            if (!is_in_shadow(p, light, center, radius)){
                float diff = fmax(0.0, vdot(n, light));
                brightness = 0.2f + 0.8f * diff;
            }
            int check = (int)((double)floorf(p.x) + (double)floorf(p.z)) & 1;
            float col = (check ? 0.4f : 0.9f) * brightness;
            return vc(col, col, col);
        }
    }
    return sky_color(ray);
}

static float img[600][800][3];

static void write_image(const char *fn, int W, int H){
    FILE *f = fopen(fn, "w");
    if (!f){ fprintf(stderr, "Error: Could not open file %s for writing\n", fn); return; }
    fprintf(f, "P3\n%d %d\n255\n", W, H);
    for (int y=0; y<H; y++){
        for (int x=0; x<W; x++){
            int r = (int)((float)fmin(fmax((double)img[y][x][0], 0.0), 1.0) * 255.99f);
            int g = (int)((float)fmin(fmax((double)img[y][x][1], 0.0), 1.0) * 255.99f);
            int b = (int)((float)fmin(fmax((double)img[y][x][2], 0.0), 1.0) * 255.99f);
            fprintf(f, "%d %d %d\n", r, g, b);
        }
    }
    fclose(f);
    fprintf(stderr, "Wrote image to %s\n", fn);
}

int main(void){
    int W = 800, H = 600;
    Vec light = vnorm(vc(1.0f, 1.0f, -1.0f));
    Vec center = vc(0.0f, -0.5f, -5.0f);
    float radius = 1.0f;
    Vec origin = vc(0.0f, 0.0f, 0.0f);

    fprintf(stderr, "Creating high-resolution image: %dx%d\n", W, H);
    fprintf(stderr, "This will be downsampled with ffmpeg after rendering\n");
    fprintf(stderr, "Rendering high-resolution image...\n");
    for (int y=0; y<H; y++){
        fprintf(stderr, "\rProgress: %.1f%%", 100.0f * y / 600.0f);
        for (int x=0; x<W; x++){
            float u = (float)x / 799.0f;
            float px = u * (8.0f/3.0f) - (4.0f/3.0f);
            float py = 2.0f * (1.0f - (float)y / 599.0f) - 1.0f;
            Vec dir = vc(px, py, -1.0f);
            Ray ray = ray_create(origin, dir);
            Vec col = trace(ray, center, radius, light);
            img[y][x][0] = col.x;
            img[y][x][1] = col.y;
            img[y][x][2] = col.z;
        }
    }
    fprintf(stderr, "\nRendering complete\n");
    write_image("image.ppm", W, H);
    fprintf(stderr, "Done.\n");
    return 0;
}

